INSERT INTO dawah_articles (category_id, slug, title_ar, summary_ar, body_ar, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='entering-islam'), 'what-is-islam',
'ما هو الإسلام؟',
'مدخل عام مبسّط لمعنى الإسلام وأركانه الأساسية، لمن يتعرّف عليه لأول مرة.',
'الإسلام في اللغة العربية يعني الاستسلام والانقياد بسلام، وشرعًا هو الدين الذي أوحاه الله لمحمد ﷺ خاتمًا لسلسلة الرسالات السماوية السابقة (كرسالات نوح وإبراهيم وموسى وعيسى عليهم السلام). جوهر الإسلام بسيط ومباشر: الإيمان بإله واحد لا شريك له، خالق كل شيء ومدبّره، تُعبَد وحدها بلا وسيط بينك وبينها. يقوم الإسلام على خمسة أركان عملية: الشهادتان (النطق بالإيمان بالله ورسوله)، والصلاة (خمس مرات يوميًا)، والزكاة (مساعدة مالية منظَّمة للمحتاجين)، والصيام (شهر رمضان سنويًا)، والحج (رحلة لمكة مرة في العمر لمن استطاع). ويقوم على ستة أركان اعتقادية: الإيمان بالله، وملائكته، وكتبه المنزلة، ورسله، واليوم الآخر، والقدر خيره وشرّه. الإسلام ليس مجرد شعائر تُؤدَّى، بل تصوّر شامل للحياة يربط العبادة بالأخلاق اليومية: الصدق، والعدل، والرحمة، وحسن معاملة الناس جميعًا. وهو دين يخاطب العقل ويدعو إلى التفكر لا الإيمان الأعمى، ويرحّب بأسئلة كل باحث صادق عن الحقيقة.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'who-is-muhammad',
'من هو محمد ﷺ؟',
'نبذة موجزة عن سيرة النبي محمد ﷺ ومكانته في الإسلام.',
'محمد بن عبد الله ﷺ وُلد في مكة، وهو في التصور الإسلامي خاتم الأنبياء والمرسلين، بُعث للناس كافة لا لقوم بعينهم، وليس مؤسسًا لدين جديد بقدر ما هو مبلّغ لرسالة التوحيد ذاتها التي حملها الأنبياء السابقون. عاش قبل بعثته بالنبوة معروفًا بين قومه بالصدق والأمانة حتى لُقِّب بـ"الصادق الأمين"، وتلقى الوحي وعمره أربعون عامًا، واستمرت رسالته ثلاثًا وعشرين سنة تنقّل خلالها بين مكة والمدينة، وواجه أذى ومقاطعة اجتماعية شديدة في مكة قبل أن تستقر دولة الإسلام الأولى في المدينة. يؤمن المسلمون بنبوته لا بألوهيته: هو بشر رسول، لا يُعبَد ولا يُدعى من دون الله، لكنه يُتَّبع هديه وسنته باعتبارها بيانًا عمليًا لكيفية تطبيق الوحي في الحياة. اتّسمت سيرته بالرحمة حتى مع من عاداه، والعدل في الحكم، والزهد في الدنيا رغم تمكّنه السياسي في أواخر حياته. القرآن نفسه يصفه بأنه "رحمة للعالمين"، لا لأمة أو زمن بعينه.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='quran'), 'introduction-to-quran',
'مدخل إلى القرآن الكريم',
'نبذة عن القرآن: نزوله وجمعه ومكانته كمصدر أول للتشريع في الإسلام.',
'القرآن الكريم هو كلام الله المُنزَل على النبي محمد ﷺ عبر الوحي، على مدى ثلاث وعشرين سنة، وهو المصدر الأول للتشريع الإسلامي. نزل باللغة العربية، ويؤمن المسلمون أنه محفوظ من التحريف بطريقتين متلازمتين: الكتابة الفورية في عهد النبي ﷺ، والحفظ الشفهي المتواتر عبر ملايين الحفّاظ جيلًا بعد جيل حتى اليوم. يتناول القرآن موضوعات متعددة: العقيدة والتوحيد، القصص التاريخية للأمم والأنبياء السابقين، الأحكام التشريعية (العبادات والمعاملات)، والأخلاق والقيم. لمن لا يقرأ العربية، تتوفر ترجمات لمعاني القرآن (لا القرآن نفسه، إذ يرى المسلمون أن الترجمة تنقل المعنى التقريبي لا النص المعجز بلغته الأصلية) بلغات كثيرة تساعد على فهم المضمون العام. لا يُشترط على من يتعرّف على الإسلام حديثًا أن يقرأ القرآن كاملًا أو يفهم كل تفاصيله فورًا؛ القراءة المتدرجة بتدبر، ولو آيات قليلة يوميًا، هي الطريق الموصى به للتعرف عليه تدريجيًا.',
'draft', false)
